from outlines import prompts
from outlines.prompts import register_filter, unregister_filter

register_filter('shout', lambda s: s.upper())

@prompts.prompt
def greet(text):
    '''{{ text | shout }}'''

print(greet('hello'))

unregister_filter('shout')

@prompts.prompt
def greet2(text):
    '''{{ text | shout }}'''

try:
    print(greet2('hello'))
except Exception as e:
    print('Expected error for new template after unregister:', type(e).__name__)
